sql:
SELECT location_name 
FROM places 
WHERE city = 'Chicago';

SELECT event_id, event_time, place_id, speed, is_incident
FROM traffic_events
WHERE is_incident = 1 AND speed > 50;

SELECT event_type_id, event_type_name, description
FROM event_types
WHERE event_type_id > 5 AND description LIKE '%measurement%';

SELECT DISTINCT p.location_name
FROM event_statistics es
JOIN places p ON es.place_id = p.place_id;

SELECT MAX(speed_limit)
FROM speed_limit_zones
WHERE place_id = 0;
